// oauth-server.js
const express = require('express');
const Redis = require('ioredis');
const crypto = require('crypto');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcryptjs');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const redis = new Redis({
  host: process.env.REDIS_HOST || '127.0.0.1',
  port: process.env.REDIS_PORT || 6379,
});

// Configuration
const CONFIG = {
  ACCESS_TOKEN_SECRET: process.env.ACCESS_TOKEN_SECRET || 'access-token-secret-change-in-production',
  ACCESS_TOKEN_EXPIRY: '15m',
  ACCESS_TOKEN_EXPIRY_SECONDS: 900,
  REFRESH_TOKEN_EXPIRY_SECONDS: 365 * 24 * 60 * 60, // 1 year
  PORT: process.env.PORT || 3000,
};

// In-memory user store (replace with database in production)
const users = new Map();
// In-memory client store (replace with database in production)
const clients = new Map();

// Seed a test client
clients.set('test-client-id', {
  clientId: 'test-client-id',
  clientSecret: bcrypt.hashSync('test-client-secret', 10),
  redirectUris: ['http://localhost:3000/callback'],
  grants: ['authorization_code', 'password', 'refresh_token'],
});

// Seed a test user
users.set('testuser', {
  username: 'testuser',
  password: bcrypt.hashSync('testpassword', 10),
  email: 'test@example.com',
  id: uuidv4(),
});

// Authorization codes store (short-lived, in Redis)
const AUTH_CODE_PREFIX = 'auth_code:';
const REFRESH_TOKEN_PREFIX = 'refresh_token:';
const USER_REFRESH_TOKENS_PREFIX = 'user_refresh_tokens:';

// Helper: Generate a cryptographically secure random token
function generateToken() {
  return crypto.randomBytes(48).toString('hex');
}

// Helper: Generate an access token (JWT)
function generateAccessToken(userId, clientId, scope) {
  return jwt.sign(
    {
      sub: userId,
      client_id: clientId,
      scope: scope || '',
      type: 'access_token',
      jti: uuidv4(),
    },
    CONFIG.ACCESS_TOKEN_SECRET,
    { expiresIn: CONFIG.ACCESS_TOKEN_EXPIRY }
  );
}

// Helper: Store refresh token in Redis
async function storeRefreshToken(token, data) {
  const key = `${REFRESH_TOKEN_PREFIX}${token}`;
  await redis.setex(key, CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS, JSON.stringify(data));

  // Track refresh tokens per user for potential revocation
  const userKey = `${USER_REFRESH_TOKENS_PREFIX}${data.userId}`;
  await redis.sadd(userKey, token);
  await redis.expire(userKey, CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS);
}

// Helper: Retrieve refresh token from Redis
async function getRefreshToken(token) {
  const key = `${REFRESH_TOKEN_PREFIX}${token}`;
  const data = await redis.get(key);
  if (!data) return null;
  return JSON.parse(data);
}

// Helper: Revoke a single refresh token
async function revokeRefreshToken(token) {
  const key = `${REFRESH_TOKEN_PREFIX}${token}`;
  const data = await redis.get(key);
  if (data) {
    const parsed = JSON.parse(data);
    const userKey = `${USER_REFRESH_TOKENS_PREFIX}${parsed.userId}`;
    await redis.srem(userKey, token);
  }
  await redis.del(key);
}

// Helper: Revoke all refresh tokens for a user
async function revokeAllUserRefreshTokens(userId) {
  const userKey = `${USER_REFRESH_TOKENS_PREFIX}${userId}`;
  const tokens = await redis.smembers(userKey);
  if (tokens && tokens.length > 0) {
    const pipeline = redis.pipeline();
    tokens.forEach((token) => {
      pipeline.del(`${REFRESH_TOKEN_PREFIX}${token}`);
    });
    pipeline.del(userKey);
    await pipeline.exec();
  }
}

// Helper: Validate client credentials
function validateClient(clientId, clientSecret) {
  const client = clients.get(clientId);
  if (!client) return null;
  if (clientSecret && !bcrypt.compareSync(clientSecret, client.clientSecret)) return null;
  return client;
}

// Helper: Validate user credentials
function validateUser(username, password) {
  const user = users.get(username);
  if (!user) return null;
  if (!bcrypt.compareSync(password, user.password)) return null;
  return user;
}

// Middleware: Authenticate client from request
function authenticateClient(req, res, next) {
  let clientId, clientSecret;

  // Check Authorization header (Basic auth)
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    const parts = decoded.split(':');
    clientId = decodeURIComponent(parts[0]);
    clientSecret = decodeURIComponent(parts.slice(1).join(':'));
  } else {
    // Check request body
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  if (!clientId) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication required.' });
  }

  const client = validateClient(clientId, clientSecret);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials.' });
  }

  req.client = client;
  next();
}

// Middleware: Verify access token
function verifyAccessToken(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Access token required.' });
  }

  const token = authHeader.slice(7);
  try {
    const decoded = jwt.verify(token, CONFIG.ACCESS_TOKEN_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'invalid_token', error_description: 'Access token has expired.' });
    }
    return res.status(401).json({ error: 'invalid_token', error_description: 'Invalid access token.' });
  }
}

