// Authorization Endpoint POST (handle login + consent)
app.post('/authorize', async (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state, username, password, action } = req.body;

  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }

  const finalRedirectUri = redirect_uri || client.redirectUris[0];

  if (action === 'deny') {
    const params = new URLSearchParams({ error: 'access_denied' });
    if (state) params.append('state', state);
    return res.redirect(`${finalRedirectUri}?${params.toString()}`);
  }

  const user = validateUser(username, password);
  if (!user) {
    return res.status(401).send('Invalid credentials. <a href="javascript:history.back()">Try again</a>');
  }

  // Generate authorization code
  const authCode = generateToken();
  const codeData = {
    clientId: client_id,
    userId: user.id,
    username: user.username,
    redirectUri: finalRedirectUri,
    scope: scope || '',
    createdAt: Date.now(),
  };

  // Store authorization code in Redis with short TTL (10 minutes)
  await redis.setex(`${AUTH_CODE_PREFIX}${authCode}`, 600, JSON.stringify(codeData));

  const params = new URLSearchParams({ code: authCode });
  if (state) params.append('state', state);
  res.redirect(`${finalRedirectUri}?${params.toString()}`);
});

// Token Endpoint
app.post('/token', authenticateClient, async (req, res) => {
  const { grant_type } = req.body;

  switch (grant_type) {
    case 'authorization_code':
      return handleAuthorizationCodeGrant(req, res);
    case 'password':
      return handlePasswordGrant(req, res);
    case 'refresh_token':
      return handleRefreshTokenGrant(req, res);
    default:
      return res.status(400).json({ error: 'unsupported_grant_type', error_description: `Grant type '${grant_type}' is not supported.` });
  }
});

// Handle Authorization Code Grant
async function handleAuthorizationCodeGrant(req, res) {
  const { code, redirect_uri } = req.body;
  const client = req.client;

  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Authorization code is required.' });
  }

  // Retrieve and delete the authorization code (one-time use)
  const codeKey = `${AUTH_CODE_PREFIX}${code}`;
  const codeDataStr = await redis.get(codeKey);
  if (!codeDataStr) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code is invalid or expired.' });
  }

  // Delete immediately to prevent reuse
  await redis.del(codeKey);

  const codeData = JSON.parse(codeDataStr);

  // Validate the code belongs to this client
  if (codeData.clientId !== client.clientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code was not issued to this client.' });
  }

  // Validate redirect_uri matches
  if (redirect_uri && redirect_uri !== codeData.redirectUri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Redirect URI mismatch.' });
  }

  // Generate tokens
  const accessToken = generateAccessToken(codeData.userId, client.clientId, codeData.scope);
  const refreshToken = generateToken();

  // Store refresh token in Redis with 1 year TTL
  await storeRefreshToken(refreshToken, {
    userId: codeData.userId,
    username: codeData.username,
    clientId: client.clientId,
    scope: codeData.scope,
    createdAt: Date.now(),
    lastUsedAt: Date.now(),
    useCount: 0,
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: CONFIG.ACCESS_TOKEN_EXPIRY_SECONDS,
    refresh_token: refreshToken,
    scope: codeData.scope,
  });
}

// Handle Resource Owner Password Credentials Grant
async function handlePasswordGrant(req, res) {
  const { username, password, scope } = req.body;
  const client = req.client;

  if (!client.grants.includes('password')) {
    return res.status(400).json({ error: 'unauthorized_client', error_description: 'Client is not authorized for password grant.' });
  }

  if (!username || !password) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Username and password are required.' });
  }

  const user = validateUser(username, password);
  if (!user) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid user credentials.' });
  }

  // Generate tokens
  const accessToken = generateAccessToken(user.id, client.clientId, scope);
  const refreshToken = generateToken();

  // Store refresh token in Redis with 1 year TTL
  await storeRefreshToken(refreshToken, {
    userId: user.id,
    username: user.username,
    clientId: client.clientId,
    scope: scope || '',
    createdAt: Date.now(),
    lastUsedAt: Date.now(),
    useCount: 0,
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: CONFIG.ACCESS_TOKEN_EXPIRY_SECONDS,
    refresh_token: refreshToken,
    scope: scope || '',
  });
}

// Handle Refresh Token Grant (reuse without rotation)
async function handleRefreshTokenGrant(req, res) {
  const { refresh_token, scope } = req.body;
  const client = req.client;

  if (!client.grants.includes('refresh_token')) {
    return res.status(400).json({ error: 'unauthorized_client', error_description: 'Client is not authorized for refresh_token grant.' });
  }

  if (!refresh_token) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Refresh token is required.' });
  }

  // Retrieve refresh token data from Redis
  const tokenData = await getRefreshToken(refresh_token);
  if (!tokenData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Refresh token is invalid or expired.' });
  }

  // Validate the refresh token belongs to this client
  if (tokenData.clientId !== client.clientId) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Refresh token was not issued to this client.' });
  }

  // Determine the effective scope
  let effectiveScope = tokenData.scope;
  if (scope) {
    // Requested scope must be a subset of the original scope
    const originalScopes = new Set(tokenData.scope.split(' ').filter(Boolean));
    const requestedScopes = scope.split(' ').filter(Boolean);
    for (const s of requestedScopes) {
      if (!originalScopes.has(s)) {
        return res.status(400).json({ error: 'invalid_scope', error_description: `Scope '${s}' was not granted originally.` });
      }
    }
    effectiveScope = scope;
  }

  // Update the refresh token metadata (reuse the same token, no rotation)
  tokenData.lastUsedAt = Date.now();
  tokenData.useCount = (tokenData.useCount || 0) + 1;

  // Re-store with the remaining TTL (or reset to full TTL for convenience)
  const key = `${REFRESH_TOKEN_PREFIX}${refresh_token}`;
  const remainingTTL = await redis.ttl(key);
  // Keep the original TTL - don't extend it
  if (remainingTTL > 0) {
    await redis.setex(key, remainingTTL, JSON.stringify(tokenData));
  } else {
    // Shouldn't happen if token exists, but handle gracefully
    await redis.setex(key, CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS, JSON.stringify(tokenData));
  }

  // Issue a new access token
  const accessToken = generateAccessToken(tokenData.userId, client.clientId, effectiveScope);

  // Return the SAME refresh token (no rotation)
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: CONFIG.ACCESS_TOKEN_EXPIRY_SECONDS,
    refresh_token: refresh_token, // Same token reused
    scope: effectiveScope,
  });
}

// Token Revocation Endpoint (RFC 7009)
app.post('/revoke', authenticateClient, async (req, res) => {
  const { token, token_type_hint } = req.body;

  if (!token) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Token is required.' });
  }

  // Try to revoke as refresh token
  const refreshTokenData = await getRefreshToken(token);
  if (refreshTokenData) {
    if (refreshTokenData.clientId !== req.client.clientId) {
      // Token doesn't belong to this client, but per RFC 7009 we return 200 anyway
      return res.sendStatus(200);
    }
    await revokeRefreshToken(token);
    return res.sendStatus(200);
  }

  // If it's an access token (JWT), we can't really revoke it without a blacklist
  // For simplicity, just return 200
  res.sendStatus(200);
});

